1	import { useCallback, useMemo, useState } from 'react';
2	import {
3	  KeyboardAvoidingView,
4	  Platform,
5	  SafeAreaView,
6	  ScrollView,
7	  StyleSheet,
8	  Text,
9	  TextInput,
10	  type TextInputProps,
11	  View,
12	} from 'react-native';
13	import { useRouter } from 'expo-router';
14	import { colors, radii, shadows, spacing } from '@/design/tokens';
15	import { textStyles } from '@/design/typography';
16	import { ButtonPrimary } from '@/components/primitives/Button';
17	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
18	import { useToast } from '@/components/primitives/Toast';
19	import { useAuth, type AuthUser } from '@/lib/auth';
20	import { supabase } from '@/lib/supabase';
21	
22	// US-034 — Creator signup. Username + at least one handle (TikTok and/or
23	// Instagram). Submit calls auth-signup-creator; the edge function holds the
24	// request open up to APIFY_WAIT_SECS (60s) while it dispatches scrapes, so
25	// the submitting state renders "Pulling your stats…" with skeleton cards for
26	// each supplied handle. On success the JWT + user row is handed to the
27	// AuthProvider and we jump to the creator tab group. Inline 409 handling
28	// mirrors the US-033 lister pattern; USERNAME_TAKEN pins to the username
29	// field, HANDLE_TAKEN falls through to a toast because the edge function
30	// does not say which platform conflicted.
31	
32	type FieldKey = 'username' | 'tiktok' | 'instagram';
33	type FieldErrors = Partial<Record<FieldKey, string>>;
34	
35	const USERNAME_RE = /^[a-zA-Z0-9_]{3,32}$/;
36	const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;
37	
38	type FieldValues = { username: string; tiktok: string; instagram: string };
39	
40	function stripAt(value: string): string {
41	  return value.trim().replace(/^@+/, '').trim();
42	}
43	
44	function clientValidate(v: FieldValues): FieldErrors {
45	  const errs: FieldErrors = {};
46	  const u = v.username.trim();
47	  const tt = stripAt(v.tiktok);
48	  const ig = stripAt(v.instagram);
49	
50	  if (!u) errs.username = 'Username is required';
51	  else if (!USERNAME_RE.test(u)) errs.username = '3–32 letters, numbers, or underscores';
52	
53	  if (tt && !HANDLE_RE.test(tt)) errs.tiktok = 'Letters, numbers, underscores, or dots';
54	  if (ig && !HANDLE_RE.test(ig)) errs.instagram = 'Letters, numbers, underscores, or dots';
55	
56	  if (!tt && !ig) {
57	    const msg = 'Add at least one handle';
58	    errs.tiktok = msg;
59	    errs.instagram = msg;
60	  }
61	
62	  return errs;
63	}
64	
65	type SignupSuccess = {
66	  token: string;
67	  user_id: string;
68	  role: 'creator';
69	  metrics_status?: Record<string, unknown>;
70	};
71	
72	export default function SignupCreator() {
73	  const router = useRouter();
74	  const { signIn } = useAuth();
75	  const { show: showToast } = useToast();
76	
77	  const [username, setUsername] = useState('');
78	  const [tiktok, setTiktok] = useState('');
79	  const [instagram, setInstagram] = useState('');
80	  const [touched, setTouched] = useState<Partial<Record<FieldKey, boolean>>>({});
81	  const [serverErrors, setServerErrors] = useState<FieldErrors>({});
82	  const [submitting, setSubmitting] = useState(false);
83	
84	  const clientErrors = useMemo(
85	    () => clientValidate({ username, tiktok, instagram }),
86	    [username, tiktok, instagram],
87	  );
88	
89	  const visibleErrors: FieldErrors = {
90	    username: serverErrors.username ?? (touched.username ? clientErrors.username : undefined),
91	    tiktok: serverErrors.tiktok ?? (touched.tiktok ? clientErrors.tiktok : undefined),
92	    instagram:
93	      serverErrors.instagram ?? (touched.instagram ? clientErrors.instagram : undefined),
94	  };
95	
96	  const markTouched = useCallback((key: FieldKey) => {
97	    setTouched((t) => (t[key] ? t : { ...t, [key]: true }));
98	  }, []);
99	
100	  const updateField = useCallback(
101	    (key: FieldKey, setter: (s: string) => void) => (next: string) => {
102	      setter(next);
103	      setServerErrors((prev) => (prev[key] ? { ...prev, [key]: undefined } : prev));
104	    },
105	    [],
106	  );
107	
108	  const onSubmit = useCallback(async () => {
109	    setTouched({ username: true, tiktok: true, instagram: true });
110	    const errs = clientValidate({ username, tiktok, instagram });
111	    if (Object.keys(errs).length > 0) return;
112	
113	    const tiktokHandle = stripAt(tiktok);
114	    const instagramHandle = stripAt(instagram);
115	
116	    setServerErrors({});
117	    setSubmitting(true);
118	    try {
119	      const { data, error } = await supabase.functions.invoke<SignupSuccess>(
120	        'auth-signup-creator',
121	        {
122	          body: {
123	            username: username.trim(),
124	            ...(tiktokHandle ? { tiktok_handle: tiktokHandle } : {}),
125	            ...(instagramHandle ? { instagram_handle: instagramHandle } : {}),
126	          },
127	        },
128	      );
129	
130	      if (error) {
131	        const ctx = (error as { context?: unknown }).context;
132	        if (
133	          ctx &&
134	          typeof ctx === 'object' &&
135	          'status' in ctx &&
136	          typeof (ctx as { json?: unknown }).json === 'function'
137	        ) {
138	          const res = ctx as Response;
139	          let body: { error?: string } = {};
140	          try {
141	            body = (await res.json()) as { error?: string };
142	          } catch {
143	            // non-JSON body; fall through to generic toast
144	          }
145	          if (res.status === 409 && body.error === 'USERNAME_TAKEN') {
146	            setServerErrors({ username: 'Username already taken' });
147	            return;
148	          }
149	          if (res.status === 409 && body.error === 'HANDLE_TAKEN') {
150	            // Edge function does not identify which platform conflicted; the
151	            // creator profile screen (US-035) has the add/unlink flow that
152	            // can surface the specific collision.
153	            showToast({
154	              message: 'That handle is already linked to another account.',
155	              variant: 'error',
156	            });
157	            return;
158	          }
159	          if (res.status === 422 && body.error === 'HANDLE_REQUIRED') {
160	            const msg = 'Add at least one handle';
161	            setServerErrors({ tiktok: msg, instagram: msg });
162	            return;
163	          }
164	        }
165	        showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
166	        return;
167	      }
168	
169	      if (!data) {
170	        showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
171	        return;
172	      }
173	
174	      const nowIso = new Date().toISOString();
175	      const nextUser: AuthUser = {
176	        id: data.user_id,
177	        username: username.trim(),
178	        email: null,
179	        role: 'creator',
180	        created_at: nowIso,
181	        updated_at: nowIso,
182	        deleted_at: null,
183	      };
184	      signIn(data.token, nextUser);
185	      showToast({ message: 'Welcome', variant: 'success' });
186	      router.replace('/(creator)/feed');
187	    } catch (err) {
188	      console.error('Creator signup threw', err);
189	      showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
190	    } finally {
191	      setSubmitting(false);
192	    }
193	  }, [username, tiktok, instagram, signIn, showToast, router]);
194	
195	  if (submitting) {
196	    return <PullingStatsState tiktok={stripAt(tiktok)} instagram={stripAt(instagram)} />;
197	  }
198	
199	  return (
200	    <SafeAreaView style={styles.container}>
201	      <KeyboardAvoidingView
202	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
203	        style={styles.flex}
204	      >
205	        <ScrollView
206	          contentContainerStyle={styles.scrollContent}
207	          keyboardShouldPersistTaps="handled"
208	        >
209	          <View style={styles.header}>
210	            <Text style={[textStyles.display, styles.title]}>Creator signup</Text>
211	            <Text style={[textStyles.body, styles.subtitle]}>
212	              Pick a username and add at least one handle — we&apos;ll pull your stats.
213	            </Text>
214	          </View>
215	
216	          <View style={styles.fields}>
217	            <Field
218	              label="Username"
219	              value={username}
220	              onChange={updateField('username', setUsername)}
221	              onBlur={() => markTouched('username')}
222	              autoCapitalize="none"
223	              autoCorrect={false}
224	              autoComplete="username"
225	              placeholder="sarah_films"
226	              error={visibleErrors.username}
227	              testID="creator-signup-username"
228	            />
229	            <Field
230	              label="TikTok handle"
231	              value={tiktok}
232	              onChange={updateField('tiktok', setTiktok)}
233	              onBlur={() => markTouched('tiktok')}
234	              autoCapitalize="none"
235	              autoCorrect={false}
236	              autoComplete="off"
237	              keyboardType="default"
238	              placeholder="@sarahfilms"
239	              mono
240	              error={visibleErrors.tiktok}
241	              testID="creator-signup-tiktok"
242	            />
243	            <Field
244	              label="Instagram handle"
245	              value={instagram}
246	              onChange={updateField('instagram', setInstagram)}
247	              onBlur={() => markTouched('instagram')}
248	              autoCapitalize="none"
249	              autoCorrect={false}
250	              autoComplete="off"
251	              keyboardType="default"
252	              placeholder="@sarahfilms"
253	              mono
254	              error={visibleErrors.instagram}
255	              testID="creator-signup-instagram"
256	            />
257	          </View>
258	
259	          <ButtonPrimary
260	            label="Continue"
261	            onPress={onSubmit}
262	            loading={submitting}
